@@ -85,6 +85 @@ private static async Task SendFileAsyncCore(HttpResponse response, IFileInfo file
+        // Set Content-Length when the file length is known, the response has not yet started,
+        // and no other Transfer-Encoding is configured.
+        if (!response.HasStarted && string.IsNullOrEmpty(response.Headers.TransferEncoding))
+        {
+            response.ContentLength = count ?? (file.Length - offset);
+        }
@@ -112,6 +112 @@ private static async Task SendFileAsyncCore(HttpResponse response, string fileName
+        if (!response.HasStarted && string.IsNullOrEmpty(response.Headers.TransferEncoding))
+        {
+            var contentLength = count ?? (new FileInfo(fileName).Length - offset);
+            if (contentLength >= 0)
+            {
+                response.ContentLength = contentLength;
+            }
+        }
